230	/** Up-to-two-letter initials for the avatar (e.g. "Dev Bypass User" → "DB"). */
231	function initialsOf(name: string): string {
232	  const parts = name.trim().split(/\s+/).filter(Boolean);
233	  if (parts.length === 0) return '?';
234	  return (parts[0][0] + (parts.length > 1 ? parts[parts.length - 1][0] : '')).toUpperCase();
235	}
