89	      ),
90	    },
91	  ];
92	  return (
93	    <Table<AssetSummary>
94	      scroll={{ x: 'max-content' }}
95	      rowKey="id"
96	      size="middle"
97	      columns={columns}
98	      dataSource={assets}
99	      pagination={false}
100	      onRow={(asset) => ({
101	        onClick: () => onOpen(asset.id),
102	        style: { cursor: 'pointer' },
103	      })}
104	    />
105	  );
106	}
