54	        >
55	          Assets
56	        </Button>
57	      </div>
58	      <AsyncBody state={state} loadingText="Loading asset…" errorTitle="Failed to load asset">
59	        {(asset) => (
60	          <AssetDetailBody
61	            asset={asset}
62	            onOpenRun={(id) => navigate(`/results/${id}`)}
