import type { LineageEdge, LineageNode } from '../../api/assets';

/**
 * Lineage graph layout (#805) — pure, so the geometry is unit-testable without
 * rendering anything (kept out of the `.tsx`).
 *
 * The asset under view sits in the middle; its **upstream** provenance fans out to
 * the left and its **downstream** blast radius to the right, one column per hop.
 * The backend gives us each neighbour's hop `depth` and the *real* edges between
 * them (`lineage_edges`), so a depth-2 node is drawn hanging off the depth-1 node
 * it actually descends from — never off the centre it has no edge to.
 *
 * Signed-depth columns: upstream depth `d` → column `-d`, the centre → `0`,
 * downstream depth `d` → column `+d`. Sorting the distinct columns left-to-right
 * therefore lays provenance → asset → consumers out in reading order.
 *
 * No graph library: the layout is a layered DAG we can place ourselves, and an
 * inline SVG scrolls horizontally inside its card on a phone far more simply than
 * a pan/zoom canvas would (and adds no dependency to license-check).
 */

export const NODE_W = 190;
export const NODE_H = 52;
const COL_GAP = 72;
const ROW_GAP = 14;
const PAD = 12;

export interface LaidOutNode {
  id: string;
  name: string;
  namespace: string;
  env: string | null;
  isMonitored: boolean;
  /** The asset under view — rendered as the anchor and not clickable. */
  isCenter: boolean;
  x: number;
  y: number;
}

export interface LaidOutEdge {
  id: string;
  /** SVG cubic-bezier `d`, left edge of the source to right edge of the target. */
  path: string;
}

export interface LineageLayout {
  nodes: LaidOutNode[];
  edges: LaidOutEdge[];
  width: number;
  height: number;
}

/** The asset under view, as the graph's centre node. */
export interface CenterAsset {
  id: string;
  name: string;
  namespace: string;
  env: string | null;
}

/**
 * Lay the neighbourhood out into hop columns and bezier edges.
 *
 * Edges whose endpoints aren't both in the neighbourhood are dropped rather than
 * drawn to nowhere (defensive: the backend only returns edges it traversed, but a
 * dangling edge must never throw or render a line into empty space).
 */
export function buildLineageLayout(
  center: CenterAsset,
  upstream: LineageNode[],
  downstream: LineageNode[],
  edges: LineageEdge[],
): LineageLayout {
  // Signed-depth column per node: upstream left (negative), downstream right.
  const placed: { node: LaidOutNode; col: number }[] = [
    {
      node: { ...center, isMonitored: true, isCenter: true, x: 0, y: 0 },
      col: 0,
    },
  ];
  for (const n of upstream) {
    placed.push({
      node: {
        id: n.id,
        name: n.name,
        namespace: n.namespace,
        env: n.env,
        isMonitored: n.is_monitored,
        isCenter: false,
        x: 0,
        y: 0,
      },
      col: -n.depth,
    });
  }
  for (const n of downstream) {
    placed.push({
      node: {
        id: n.id,
        name: n.name,
        namespace: n.namespace,
        env: n.env,
        isMonitored: n.is_monitored,
        isCenter: false,
        x: 0,
        y: 0,
      },
      col: n.depth,
    });
  }

  // Group by column, then order the columns left → right by signed depth.
  const byCol = new Map<number, LaidOutNode[]>();
  for (const { node, col } of placed) {
    const bucket = byCol.get(col);
    if (bucket) bucket.push(node);
    else byCol.set(col, [node]);
  }
  const cols = [...byCol.keys()].sort((a, b) => a - b);

  const colHeight = (n: number) => n * NODE_H + Math.max(0, n - 1) * ROW_GAP;
  const tallest = Math.max(...cols.map((c) => colHeight(byCol.get(c)?.length ?? 0)));

  cols.forEach((col, i) => {
    const nodes = byCol.get(col) ?? [];
    // Centre each column vertically against the tallest one, so the graph reads
    // as a spine rather than a ragged top-aligned stack.
    const top = PAD + (tallest - colHeight(nodes.length)) / 2;
    nodes.forEach((node, j) => {
      node.x = PAD + i * (NODE_W + COL_GAP);
      node.y = top + j * (NODE_H + ROW_GAP);
    });
  });

  const nodes = placed.map((p) => p.node);
  const byId = new Map(nodes.map((n) => [n.id, n]));

  const laidOutEdges: LaidOutEdge[] = [];
  for (const e of edges) {
    const from = byId.get(e.source);
    const to = byId.get(e.target);
    if (!from || !to) continue; // dangling — never draw a line into empty space
    laidOutEdges.push({ id: `${e.source}->${e.target}`, path: bezier(from, to) });
  }

  return {
    nodes,
    edges: laidOutEdges,
    width: PAD * 2 + cols.length * NODE_W + Math.max(0, cols.length - 1) * COL_GAP,
    height: PAD * 2 + tallest,
  };
}

/** A cubic bezier from the source node's right edge to the target's left edge. */
function bezier(from: LaidOutNode, to: LaidOutNode): string {
  const sx = from.x + NODE_W;
  const sy = from.y + NODE_H / 2;
  const tx = to.x;
  const ty = to.y + NODE_H / 2;
  // Clamped control offset: keeps the curve readable even for a same-column or
  // backwards edge, where (tx - sx) would otherwise be zero or negative.
  const dx = Math.max(24, (tx - sx) / 2);
  return `M ${sx} ${sy} C ${sx + dx} ${sy}, ${tx - dx} ${ty}, ${tx} ${ty}`;
}

import { ApartmentOutlined } from '@ant-design/icons';
import { Card, Empty, Flex, Tag, Typography } from 'antd';
import { useMemo } from 'react';

import type { LineageEdge, LineageNode } from '../../api/assets';
import { BRAND } from '../../theme';
import { type CenterAsset, NODE_H, NODE_W, buildLineageLayout } from './lineageGraph';

/**
 * Lineage graph (#805) — one left-to-right DAG replacing the two separate
 * upstream/downstream list boxes: provenance on the left, the asset under view in
 * the middle, blast radius on the right, one column per hop.
 *
 * Nodes are clickable and navigate to that asset. Depth ≥2 comes for free from the
 * existing blast-radius BFS, which now also hands back each node's hop depth and
 * the real edges between them — so a depth-2 node is drawn hanging off the node it
 * actually descends from.
 *
 * Plain inline SVG, no graph library: the layout is a layered DAG we place
 * ourselves (`lineageGraph.ts`), and an SVG in an `overflow-x` container scrolls
 * horizontally inside the card on a phone without ever widening the page — which a
 * pan/zoom canvas makes harder, not easier. It also keeps the dependency count
 * (and the ADR 0031 licence surface) at zero.
 */
export function LineageGraph({
  center,
  upstream,
  downstream,
  edges,
  onOpenAsset,
}: {
  center: CenterAsset;
  upstream: LineageNode[];
  downstream: LineageNode[];
  edges: LineageEdge[];
  onOpenAsset: (assetId: string) => void;
}) {
  const layout = useMemo(
    () => buildLineageLayout(center, upstream, downstream, edges),
    [center, upstream, downstream, edges],
  );
  const isolated = upstream.length === 0 && downstream.length === 0;

  return (
    <Card
      size="small"
      title={
        <Flex gap={8} align="center">
          <ApartmentOutlined />
          Lineage
        </Flex>
      }
      extra={
        !isolated && (
          <Typography.Text type="secondary" style={{ fontSize: 12 }}>
            {upstream.length} upstream · {downstream.length} downstream
          </Typography.Text>
        )
      }
    >
      {isolated ? (
        <Empty
          image={Empty.PRESENTED_IMAGE_SIMPLE}
          description="No lineage recorded for this asset."
        />
      ) : (
        // The ONLY scroll container: a wide graph scrolls inside the card, so the
        // page itself never overflows horizontally on a phone (#805).
        <div style={{ overflowX: 'auto', overflowY: 'hidden' }}>
          <svg
            width={layout.width}
            height={layout.height}
            role="img"
            aria-label={`Lineage graph: ${upstream.length} upstream and ${downstream.length} downstream assets around ${center.name}`}
            style={{ display: 'block' }}
          >
            <defs>
              <marker
                id="dq-lineage-arrow"
                markerWidth="8"
                markerHeight="8"
                refX="7"
                refY="4"
                orient="auto"
              >
                <path d="M0,0 L8,4 L0,8 z" fill="#c4c8cf" />
              </marker>
            </defs>

            {/* Edges first so the node cards sit on top of the curves. */}
            {layout.edges.map((e) => (
              <path
                key={e.id}
                d={e.path}
                fill="none"
                stroke="#c4c8cf"
                strokeWidth={1.5}
                markerEnd="url(#dq-lineage-arrow)"
              />
            ))}

            {layout.nodes.map((n) => (
              <GraphNode
                key={n.id}
                node={n}
                onOpen={n.isCenter ? undefined : () => onOpenAsset(n.id)}
              />
            ))}
          </svg>
        </div>
      )}

      {/* The monitored/unmonitored distinction the old list boxes carried as tags
          — kept as a legend so the graph's border styling stays readable. */}
      {!isolated && (
        <Flex gap={16} align="center" style={{ marginTop: 8 }} wrap>
          <Flex gap={6} align="center">
            <Tag color="blue" style={{ marginInlineEnd: 0 }}>
              Monitored
            </Tag>
            <Typography.Text type="secondary" style={{ fontSize: 12 }}>
              has a suite targeting it
            </Typography.Text>
          </Flex>
          <Typography.Text type="secondary" style={{ fontSize: 12 }}>
            Click any node to open that asset.
          </Typography.Text>
        </Flex>
      )}
    </Card>
  );
}

/** One node card, drawn in SVG. Clickable (and keyboard-operable) unless it's the
 *  centre — you are already looking at that asset. */
function GraphNode({
  node,
  onOpen,
}: {
  node: ReturnType<typeof buildLineageLayout>['nodes'][number];
  onOpen?: () => void;
}) {
  const interactive = onOpen !== undefined;
  return (
    <g
      transform={`translate(${node.x}, ${node.y})`}
      onClick={onOpen}
      onKeyDown={
        interactive
          ? (e) => {
              if (e.key === 'Enter' || e.key === ' ') {
                e.preventDefault();
                onOpen();
              }
            }
          : undefined
      }
      role={interactive ? 'button' : undefined}
      tabIndex={interactive ? 0 : undefined}
      aria-label={interactive ? `Open asset ${node.name}` : undefined}
      style={{ cursor: interactive ? 'pointer' : 'default' }}
    >
      <title>{`${node.name}\n${node.namespace}`}</title>
      <rect
        width={NODE_W}
        height={NODE_H}
        rx={8}
        fill={node.isCenter ? BRAND.selectedBg : '#ffffff'}
        stroke={node.isCenter ? BRAND.primary : node.isMonitored ? '#91caff' : BRAND.border}
        strokeWidth={node.isCenter ? 2 : 1}
      />
      <text
        x={10}
        y={21}
        fontSize={12}
        fontWeight={600}
        fill={BRAND.ink}
        style={{ pointerEvents: 'none' }}
      >
        {truncate(leafName(node.name), 24)}
      </text>
      <text x={10} y={38} fontSize={10} fill="#8c8c8c" style={{ pointerEvents: 'none' }}>
        {truncate(node.env ? `${node.env} · ${node.namespace}` : node.namespace, 28)}
      </text>
    </g>
  );
}

/** The last dotted/slashed segment — the table/file, not the whole path. The full
 *  identity stays in the node's <title> tooltip. */
function leafName(name: string): string {
  const sep = name.includes('/') ? '/' : '.';
  const parts = name.split(sep).filter(Boolean);
  return parts.length > 0 ? parts[parts.length - 1] : name;
}

function truncate(text: string, max: number): string {
  return text.length > max ? `${text.slice(0, max - 1)}…` : text;
}

