40	  canManage,
41	  onClose,
42	}: {
43	  open: boolean;
44	  suiteId: string;
45	  /** The suite's `created_by` — the owner can't be added as a share. */
46	  ownerId: string;
47	  canManage: boolean;
48	  onClose: () => void;
49	}) {
