51	    // `destroyOnHidden` unmounts the body on close, so it (and its share-list
52	    // fetch) starts fresh on each open — matching the other drawers in the app.
53	    <Drawer title="Share suite" open={open} onClose={onClose} size={480} destroyOnHidden>
