60	  suiteId,
61	  ownerId,
62	  canManage,
63	}: {
64	  suiteId: string;
65	  ownerId: string;
66	  canManage: boolean;
67	}) {
68	  const { state, reload } = useAsyncData(() => listShares(suiteId));
69	  // Best-effort UX lock on the signed-in user's own row (OIDC UPN ≈ their share
70	  // `email`): a non-owner admin self-revoking/-downgrading would brick the panel
71	  // (every later mutation 403s). The durable guard is server-side
72	  // (share_service._reject_self_target) since UPN can differ from mail and the
73	  // API is reachable directly; this just hides the footgun in the common case. #240.
74	  const currentEmail = useCurrentUser()?.username;
