76	  return (
77	    <AsyncBody
78	      state={state}
79	      loadingText="Loading collaborators…"
80	      errorTitle="Failed to load collaborators"
81	    >
82	      {(shares) => (
83	        <Flex vertical gap={16}>
84	          {canManage && (
85	            <AddCollaborator
86	              suiteId={suiteId}
87	              excludedIds={[ownerId, ...shares.map((s) => s.user_id)]}
88	              onAdded={reload}
