95	              dataSource={shares}
96	              renderItem={(share) => (
97	                <ShareRow
98	                  key={share.user_id}
99	                  suiteId={suiteId}
100	                  share={share}
101	                  canManage={canManage}
102	                  isSelf={
103	                    !!currentEmail && share.email.toLowerCase() === currentEmail.toLowerCase()
104	                  }
