116	function ShareRow({
117	  suiteId,
118	  share,
119	  canManage,
120	  isSelf,
121	  onChanged,
122	}: {
123	  suiteId: string;
124	  share: Share;
125	  canManage: boolean;
126	  /** This row is the signed-in user — lock it so they can't remove their own access. */
127	  isSelf: boolean;
128	  onChanged: () => void;
129	}) {
