159	  return (
160	    <SimpleList.Item
161	      actions={
162	        !canManage
163	          ? // Read-only for anyone without manage rights — including their own row.
164	            [<Tag key="perm">{share.permission}</Tag>]
165	          : isSelf
166	            ? [
167	                // A manager's own row is locked: self-revoke/-downgrade would 403
168	                // every later mutation and brick the panel (backend rejects it too,
169	                // share_service._reject_self_target). #240.
170	                <Tooltip key="perm" title="You can’t change your own access">
171	                  <Tag>{share.permission} · You</Tag>
172	                </Tooltip>,
173	              ]
174	            : [
175	                <Select
176	                  key="perm"
