205	function AddCollaborator({
206	  suiteId,
207	  excludedIds,
208	  onAdded,
209	}: {
210	  suiteId: string;
211	  /** Owner + already-shared users — hidden from the picker (backend rejects them too). */
212	  excludedIds: string[];
213	  onAdded: () => void;
214	}) {
215	  const { message } = App.useApp();
216	  const [options, setOptions] = useState<UserSummary[]>([]);
217	  const [searching, setSearching] = useState(false);
218	  const [userId, setUserId] = useState<string>();
219	  const [permission, setPermission] = useState<SharePermission>('view');
220	  const [adding, setAdding] = useState(false);
221	  const timer = useRef<ReturnType<typeof setTimeout>>(undefined);
222	  // Monotonic token so a slow earlier search can't overwrite a newer one's
223	  // results (last-wins); unmount bumps it to a sentinel to drop any in-flight
224	  // response, and clears the pending debounce so it never fires post-unmount.
225	  const latest = useRef(0);
226	  useEffect(
227	    () => () => {
228	      clearTimeout(timer.current);
229	      latest.current = -1;
230	    },
231	    [],
232	  );
233	
234	  // Debounce the directory query so a fast typist fires one search, not one per
235	  // keystroke. The 2-char floor mirrors the backend (a shorter query returns []).
236	  const onSearch = (raw: string) => {
237	    const q = raw.trim();
238	    clearTimeout(timer.current);
239	    if (q.length < 2) {
240	      setOptions([]);
241	      setSearching(false); // a pending debounce was cancelled — drop its spinner
242	      return;
243	    }
244	    setSearching(true);
245	    const token = (latest.current += 1);
246	    timer.current = setTimeout(() => {
247	      searchUsers(q)
248	        .then((users) => {
249	          if (token !== latest.current) return; // superseded by a newer search
250	          setOptions(users.filter((u) => !excludedIds.includes(u.id)));
251	        })
252	        .catch(() => {
253	          if (token === latest.current) setOptions([]);
254	        })
255	        .finally(() => {
256	          if (token === latest.current) setSearching(false);
257	        });
258	    }, 300);
259	  };
260	
261	  const onAdd = async () => {
262	    if (!userId) return;
263	    setAdding(true);
264	    try {
265	      const share = await grantShare(suiteId, { user_id: userId, permission });
266	      message.success(`${share.email}: shared`);
267	      setUserId(undefined);
268	      setOptions([]);
269	      setPermission('view');
270	      onAdded();
271	    } catch (err) {
272	      message.error(`Share failed: ${errorMessage(err)}`);
273	    } finally {
274	      setAdding(false);
275	    }
276	  };
277	
278	  return (
279	    <Flex gap={8} align="center">
280	      <Select
281	        showSearch
282	        value={userId}
283	        placeholder="Search by email or name"
284	        filterOption={false}
285	        onSearch={onSearch}
286	        onChange={setUserId}
287	        notFoundContent={searching ? <Spin size="small" /> : null}
288	        options={options.map((u) => ({
289	          value: u.id,
290	          label: u.display_name ? `${u.display_name} · ${u.email}` : u.email,
291	        }))}
292	        style={{ flex: 1 }}
293	      />
294	      <Select
295	        value={permission}
296	        options={PERMISSION_OPTIONS}
297	        onChange={setPermission}
298	        style={{ width: 110 }}
299	      />
300	      <Button type="primary" loading={adding} disabled={!userId} onClick={onAdd}>
301	        Add
302	      </Button>
303	    </Flex>
304	  );
305	}
