() => {
  const btn = Array.from(document.querySelectorAll('.ant-drawer-body button')).find(b => b.textContent?.trim() === 'Add');
  const row = btn.parentElement;                       // the <Flex> row
  const searchSel = row.querySelector('.ant-select');  // first Select (search)
  const body = document.querySelector('.ant-drawer-body');

  const before = { bodyScrollW: body.scrollWidth, bodyClientW: body.clientWidth, addRight: btn.getBoundingClientRect().right };

  // Apply exactly what the patch does: wrap + a shrinkable 160px-basis search field.
  row.style.flexWrap = 'wrap';
  searchSel.style.flex = '1 1 160px';
  searchSel.style.minWidth = '160px';

  const r = btn.getBoundingClientRect();
  const after = { bodyScrollW: body.scrollWidth, bodyClientW: body.clientWidth, addRight: r.right, addBottom: r.bottom, addVisible: r.right <= window.innerWidth && r.left >= 0 };
  return { viewport: window.innerWidth, before, after };
}

